#include <bits/stdc++.h>
using namespace std;
struct pri{
    int t,r;
}a[502];
bool cmp(pri x,pri y){
    return x.r>y.r;
}
int n,m,t[502];
int main(){
    cin>>m;
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i].t;
    for(int i=1;i<=n;i++){
        cin>>a[i].r;
        m-=a[i].r;
    }
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++){
        int tmp=a[i].t;
        while(t[tmp]==1){
        	tmp--;
		}
        if(tmp==0)continue;
        m+=a[i].r;
        t[tmp]=1;
    }
    cout<<m;
    return 0;
}
